    // --- AI estimation ---

    static async estimateNutrition(description: string, image_path?: string, single = false): Promise<MealEstimateResult> {
        const body: Record<string, string | boolean> = { description };
        if (image_path) body.image_path = image_path;
        if (single) body.single = true;

        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 180_000); // 3 min timeout

        try {
            const response = await fetch(`${HEALTH_ROOT}/food-items/estimate`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'X-Manual-AbortSignal': 'true' },
                body: JSON.stringify(body),
                signal: controller.signal,
            });
            if (!response.ok) {
                const data = await response.json().catch(() => ({}));
                throw new Error(data.error ?? `Estimation failed: ${response.status}`);
            }
            return response.json();
        } catch (err: any) {
            if (err.name === 'AbortError') {
                throw new Error('AI estimation timed out. This model might be too slow or the server is overloaded.');
            }
            throw err;
        } finally {
            clearTimeout(timeoutId);
        }
    }

