    // --- Coaching (story 074; multi-entry per date as of story 174/175) ---

    /**
     * Fetch the latest coaching entry for the given date (defaults to today).
     * With an explicit date the server returns exactly that date's latest entry
     * (or null); the bare request falls back to the most recent entry overall so
     * a teaser always has something. Used by the dashboard card.
     */
    static async fetchCoaching(date?: string): Promise<CoachingAdvice | null> {
        const url = new URL(`${HEALTH_ROOT}/coaching`);
        if (date) url.searchParams.set('date', date);
        const response = await fetch(url.toString());
        if (!response.ok) throw await apiError(response, 'Failed to fetch coaching');
        return response.json();
    }

    /**
     * Fetch every coaching entry for a date, newest first (story 175 history
     * view). Defaults to today. Empty array when the date has no entries.
     */
    static async fetchCoachingEntries(date?: string): Promise<CoachingAdvice[]> {
        const url = new URL(`${HEALTH_ROOT}/coaching/entries`);
        if (date) url.searchParams.set('date', date);
        const response = await fetch(url.toString());
        if (!response.ok) throw await apiError(response, 'Failed to fetch coaching entries');
        return response.json();
    }

    /**
     * Dates in [from, to] that have a done coaching entry — the timeline's
     * 💬 presence dots (story 258). Server-only data: callers hide the dots
     * when this fails offline.
     */
    static async fetchCoachingDates(from: string, to: string): Promise<string[]> {
        const url = new URL(`${HEALTH_ROOT}/coaching/dates`);
        url.searchParams.set('from', from);
        url.searchParams.set('to', to);
        const response = await fetch(url.toString());
        if (!response.ok) throw await apiError(response, 'Failed to fetch coaching dates');
        return response.json();
    }

    /**
     * Queue a coaching run for the given date by appending a `pending` entry
     * (server debounces an existing pending for the date). Returns 202
     * immediately — inference happens on the next scheduler heartbeat. The
     * server rejects dates more than one day in the future.
     */
    static async requestCoachingGeneration(date?: string): Promise<void> {
        const url = new URL(`${HEALTH_ROOT}/coaching/generate`);
        if (date) url.searchParams.set('date', date);
        const response = await fetch(url.toString(), { method: 'POST' });
        if (!response.ok && response.status !== 202) {
            throw await apiError(response, 'Failed to request coaching generation');
        }
    }

    /** Hand-edit an entry's advice text (story 175). Returns the updated entry. */
    static async updateCoachingAdvice(id: string, advice: string): Promise<CoachingAdvice> {
        const response = await fetch(`${HEALTH_ROOT}/coaching/${encodeURIComponent(id)}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ advice }),
        });
        if (!response.ok) throw await apiError(response, 'Failed to update coaching entry');
        return response.json();
    }
